            // Assert
            resultado.Should().NotBeNull();
            // Deve usar operador BETWEEN
            resultado.Value.where.Should().Contain($"[{DBPenhoraDicInfo.PTabelaNome}].{DBPenhoraDicInfo.QuemAtu} BETWEEN @{DBPenhoraDicInfo.QuemAtu} AND @{DBPenhoraDicInfo.QuemAtu}_end");
