            // Deve usar operador BETWEEN
            resultado.Value.where.Should().Contain($"[{DBPenhoraDicInfo.PTabelaNome}].{DBPenhoraDicInfo.Processo} BETWEEN @{DBPenhoraDicInfo.Processo} AND @{DBPenhoraDicInfo.Processo}_end");
